SELECT COUNT(*)::bigint AS cnt
FROM leads
WHERE (created_at AT TIME ZONE 'UTC')::date = (timezone('UTC', now()))::date;

SELECT COUNT(*)::bigint AS cnt
FROM leads
WHERE created_at >= (timezone('UTC', now()) - interval '7 days');

SELECT ROUND(AVG(price_total_usd)::numeric, 2) AS avg_usd
FROM leads
WHERE price_total_usd IS NOT NULL;
